chart.config_raw:
const ctx = document.getElementById('surveyChart');

    new Chart(ctx, {
      type: 'bar',
      data: {
        labels: [
          'Prompt injection vulnerability',
          'Retrieval backdoor vulnerability',
          'Inter-agent trust exploit vulnerability',
          'Adaptive attack penetration of 8 defences',
          'CrossInject effectiveness gain',
          'GPT-4 CVE exploitation success',
          'Best multimodal CAPTCHA success',
          'Devin autonomous issue resolution'
        ],
        datasets: [{
          label: 'Reported percentage',
          data: [94.4, 83.3, 100, 50, 30.1, 87, 40, 13.86],
          backgroundColor: [
            '#4dabf7',
            '#4dabf7',
            '#ff6b6b',
            '#f6ad55',
            '#f6ad55',
            '#51cf66',
            '#fab005',
            '#4dabf7'
          ],
          borderColor: [
            '#4dabf7',
            '#4dabf7',
            '#ff6b6b',
            '#f6ad55',
            '#f6ad55',
            '#51cf66',
            '#fab005',
            '#4dabf7'
          ],
          borderWidth: 1,
          borderRadius: 6
        }]
      },
      options: {
        animation: false,
        maintainAspectRatio: false,
        plugins: {
          legend: {
            display: true,
            labels: {
              color: '#4a5568',
              boxWidth: 14
            }
          },
          tooltip: {
            callbacks: {
              label: function(context) {
                return context.dataset.label + ': ' + context.raw + '%';
              }
            }
          }
        },
        scales: {
          x: {
            ticks: {
              color: '#4a5568',
              maxRotation: 55,
              minRotation: 55
            },
            grid: {
              display: false
            }
          },
          y: {
            beginAtZero: true,
            max: 100,
            ticks: {
              color: '#4a5568',
              callback: function(value) {
                return value + '%';
              }
            },
            grid: {
              color: '#e2e8f0'
            }
          }
        }
      }
    });
